import psycopg2

def createConnection(host = 'localhost', dbname='hackathon_db', username = 'admin', password = '<PASSWORD>'):
    try:
        conn = psycopg2.connect(dbname=dbname, user=username, host=host)
        return conn
    except Exception as e:
        print('Something went wrong while connecting to database',e)